#' Misclassification Bias Sensitivity Analysis
#'
#' Assesses how non-differential or differential misclassification of an
#' exposure or outcome affects observed effect estimates (OR, RR, RD).
#' Essential for studies relying on subjective classification methods
#' (e.g., Ki-67 visual estimation, morphologic grading, IHC scoring).
#' 
#'
#' @examples
#' \donttest{
#' misclassificationbias(data = data, outcome = "survival_status",
#'     exposure = "tumor_grade", outcomeLevel = "dead",
#'     exposureLevel = "high_grade",
#'     senExposure = 0.85, specExposure = 0.90)
#'}
#' @param data The data as a data frame.
#' @param outcome Binary outcome variable (e.g., recurrence, death, disease
#'   status).
#' @param outcomeLevel Level of the outcome considered as the event.
#' @param exposure Binary exposure or classification variable subject to
#'   misclassification (e.g., Ki-67 grade, morphologic classification, IHC
#'   scoring).
#' @param exposureLevel Level of the exposure considered as positive/exposed.
#' @param misclassType Non-differential: sensitivity/specificity of the
#'   classifier are the same regardless of the true outcome. Differential: error
#'   rates may differ between outcome groups.
#' @param senExposure Sensitivity of the classification method (probability of
#'   correctly classifying a truly positive case). For Ki-67 visual estimation,
#'   typically 0.70-0.90.
#' @param specExposure Specificity of the classification method (probability
#'   of correctly classifying a truly negative case).
#' @param senExposureCase Sensitivity of the classifier among cases (outcome
#'   positive). Used for differential misclassification.
#' @param specExposureCase Specificity of the classifier among cases. Used for
#'   differential misclassification.
#' @param senExposureControl Sensitivity of the classifier among controls
#'   (outcome negative). Used for differential misclassification.
#' @param specExposureControl Specificity of the classifier among controls.
#'   Used for differential misclassification.
#' @param effectMeasure Effect measure to compute and bias-adjust.
#' @param rangeAnalysis Vary sensitivity and specificity across a plausible
#'   range to show how the bias-adjusted estimate changes. Produces a contour
#'   plot.
#' @param senRange Comma-separated sensitivity values for range analysis.
#' @param specRange Comma-separated specificity values for range analysis.
#' @param nSimulations Number of Monte Carlo simulations for probabilistic
#'   bias analysis. Higher values give more stable estimates but take longer.
#' @param random_seed Random seed for reproducible simulation results.
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$notices} \tab \tab \tab \tab \tab a preformatted \cr
#'   \code{results$todo} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$observedTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$biasAnalysis} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$correctedTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$rangeTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$rangeplot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$interpretation} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$observedTable$asDF}
#'
#' \code{as.data.frame(results$observedTable)}
#'
#' @export
misclassificationbias <- function(
    data,
    outcome,
    outcomeLevel,
    exposure,
    exposureLevel,
    misclassType = "nondifferential",
    senExposure = 0.85,
    specExposure = 0.9,
    senExposureCase = 0.85,
    specExposureCase = 0.9,
    senExposureControl = 0.85,
    specExposureControl = 0.9,
    effectMeasure = "or",
    rangeAnalysis = TRUE,
    senRange = "0.70,0.75,0.80,0.85,0.90,0.95",
    specRange = "0.70,0.75,0.80,0.85,0.90,0.95",
    nSimulations = 10000,
    random_seed = 42) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("misclassificationbias requires jmvcore to be installed (restart may be required)")

    if ( ! missing(outcome)) outcome <- jmvcore::resolveQuo(jmvcore::enquo(outcome))
    if ( ! missing(exposure)) exposure <- jmvcore::resolveQuo(jmvcore::enquo(exposure))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(outcome), outcome, NULL),
            `if`( ! missing(exposure), exposure, NULL))

    for (v in outcome) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in exposure) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- misclassificationbiasOptions$new(
        outcome = outcome,
        outcomeLevel = outcomeLevel,
        exposure = exposure,
        exposureLevel = exposureLevel,
        misclassType = misclassType,
        senExposure = senExposure,
        specExposure = specExposure,
        senExposureCase = senExposureCase,
        specExposureCase = specExposureCase,
        senExposureControl = senExposureControl,
        specExposureControl = specExposureControl,
        effectMeasure = effectMeasure,
        rangeAnalysis = rangeAnalysis,
        senRange = senRange,
        specRange = specRange,
        nSimulations = nSimulations,
        random_seed = random_seed)

    analysis <- misclassificationbiasClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

